const MENU_STORAGE_KEY = "cookingMethodUploadedData_v5";
const MENU_LEGACY_STORAGE_KEYS = ["cookingMethodUploadedData_v4", "cookingMethodUploadedData_v3", "cookingMethodUploadedData_v2"];
const MENU_WINDOW_PREFIX = "COOKING_METHOD_DATA::";
const MENU_DB_NAME = "CookingMethodUploadDB";
const MENU_DB_STORE = "payload";
const MENU_REMOTE_URL = "data/today-menu.json";
const MENU_GITHUB_TOKEN_KEY = "kkulkkoori_menu_github_token";
