function menuEsc(value) {
  return String(value ?? "").replace(/[&<>"']/g, ch => ({"&":"&amp;", "<":"&lt;", ">":"&gt;", '"':"&quot;", "'":"&#39;"}[ch]));
}

function menuCleanText(value) {
  let text = String(value ?? "").replace(/\r\n/g, "\n").replace(/\r/g, "\n").replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, "");
  const lines = text.split("\n").map(line => line.replace(/\s+$/g, ""));
  const output = [];
  let blankCount = 0;
  for (const line of lines) {
    if (line.trim() === "") {
      blankCount += 1;
      if (blankCount <= 2) output.push("");
    } else {
      blankCount = 0;
      output.push(line);
    }
  }
  return output.join("\n").trim();
}

function menuCompact(value) {
  return menuCleanText(value).replace(/[ \n\t\r]/g, "");
}

function menuDateKeyAndDisplay(value) {
  const match = String(value || "").match(/(\d{4})년\s*(\d{1,2})월\s*(\d{1,2})일\s*\(?([^)]*)\)?/);
  if (!match) return null;
  const year = match[1];
  const month = String(Number(match[2])).padStart(2, "0");
  const day = String(Number(match[3])).padStart(2, "0");
  const weekday = (match[4] || "").trim();
  return { key: `${year}-${month}-${day}`, date: `${year}년 ${month}월 ${day}일${weekday ? `(${weekday})` : ""}` };
}

function updateMenuColumns(cells, cols) {
  cells.forEach((cell, index) => {
    const text = menuCompact(cell);
    if (text.includes("식사구분")) cols.meal = index;
    else if (text === "구분" || (text.endsWith("구분") && !text.includes("식사"))) cols.menu = index;
    else if (text.includes("사용재료")) cols.materials = index;
    else if (text.includes("요리방법")) cols.method = index;
  });
}

function getMenuCell(cells, index) {
  return index < cells.length ? menuCleanText(cells[index]) : "";
}

function parseMenuRows(rows) {
  const map = new Map();
  let currentKey = null;
  let currentMeal = "";
  let lastItem = null;
  const cols = { meal: 1, menu: 2, materials: 3, method: 8 };

  for (const rawRow of rows) {
    const cells = (rawRow || []).map(menuCleanText);
    if (!cells.some(Boolean)) continue;

    let foundDate = null;
    for (const cell of cells) {
      foundDate = menuDateKeyAndDisplay(cell);
      if (foundDate) break;
    }
    if (foundDate) {
      if (!map.has(foundDate.key)) map.set(foundDate.key, { key: foundDate.key, date: foundDate.date, meal: "", items: [] });
      if (currentKey !== foundDate.key) {
        currentKey = foundDate.key;
        currentMeal = "";
        lastItem = null;
      }
      continue;
    }

    if (cells.some(cell => menuCompact(cell).includes("요리방법") || menuCompact(cell) === "구분" || menuCompact(cell).includes("식사구분"))) {
      updateMenuColumns(cells, cols);
      continue;
    }

    const meal = getMenuCell(cells, cols.meal);
    const name = getMenuCell(cells, cols.menu);
    const materials = getMenuCell(cells, cols.materials);
    const method = getMenuCell(cells, cols.method);
    const joined = cells.join(" ");

    if (!meal && !name && !materials && !method) continue;
    if (meal === "청수초등학교" || meal.startsWith("비") || /^\s*-\s*\d+\s*-\s*$/.test(joined)) continue;
    if (!currentKey) continue;

    const section = map.get(currentKey);
    if (meal && (meal.includes("명") || ["중식", "석식", "조식"].some(word => meal.includes(word)))) {
      currentMeal = meal.split(/\s+/).join(" ");
      if (!section.meal) section.meal = currentMeal;
    }

    if (name && menuCompact(name) !== "구분") {
      const item = { name, materials, method, meal: currentMeal || section.meal };
      section.items.push(item);
      lastItem = item;
    } else if (lastItem && (materials || method)) {
      if (materials) lastItem.materials = menuCleanText(lastItem.materials ? `${lastItem.materials}\n${materials}` : materials);
      if (method) lastItem.method = menuCleanText(lastItem.method ? `${lastItem.method}\n${method}` : method);
    }
  }

  const parsed = [];
  for (const section of map.values()) {
    const items = [];
    for (const item of section.items) {
      item.name = menuCleanText(item.name);
      if (!item.name) continue;
      item.materials = menuCleanText(item.materials || "");
      item.method = menuCleanText(item.method || "");
      if (!item.method) {
        item.method = "등록된 조리방법 없음";
        item.muted = true;
      } else {
        item.muted = false;
      }
      items.push(item);
    }
    if (items.length) {
      section.items = items;
      parsed.push(section);
    }
  }
  parsed.sort((a, b) => a.key.localeCompare(b.key));
  return parsed;
}

function menuSheetToRows(sheet) {
  const xlsx = getXlsxLib();
  const ref = sheet["!ref"];
  if (!ref || !xlsx) return [];
  const range = xlsx.utils.decode_range(ref);
  const rows = [];
  for (let row = range.s.r; row <= range.e.r; row++) {
    const arr = [];
    for (let col = range.s.c; col <= range.e.c; col++) {
      const addr = xlsx.utils.encode_cell({ r: row, c: col });
      const cell = sheet[addr];
      arr[col] = menuCleanText(cell ? (cell.w ?? cell.v ?? "") : "");
    }
    rows.push(arr);
  }
  return rows;
}

function chooseAndParseMenuWorkbook(workbook) {
  let best = { name: "", data: [], score: -1 };
  for (const sheetName of workbook.SheetNames) {
    const sheet = workbook.Sheets[sheetName];
    const rows = menuSheetToRows(sheet);
    const data = parseMenuRows(rows);
    const flat = rows.flat().join(" ");
    const score = data.reduce((sum, section) => sum + section.items.length, 0) * 100 + (flat.match(/급식일/g) || []).length * 10 + (flat.includes("요") && flat.includes("방법") ? 5 : 0);
    if (score > best.score) best = { name: sheetName, data, score };
  }
  return best;
}

function makeMenuPayload(data, fileName) {
  return JSON.stringify({ version: 5, savedAt: Date.now(), fileName: fileName || "", data });
}

function makeMenuPayloadObject(data, fileName) {
  return { version: 5, savedAt: Date.now(), fileName: fileName || "", data };
}

function parseMenuPayload(payload) {
  if (!payload) return null;
  if (String(payload).startsWith(MENU_WINDOW_PREFIX)) payload = String(payload).slice(MENU_WINDOW_PREFIX.length);
  try {
    const parsed = JSON.parse(payload);
    if (parsed && Array.isArray(parsed.data) && parsed.data.length) return parsed;
  } catch (error) {}
  return null;
}

function normalizeMenuPayloadObject(parsed, source) {
  const data = Array.isArray(parsed) ? parsed : parsed && parsed.data;
  if (!Array.isArray(data) || !data.length) return null;
  return {
    version: parsed.version || 5,
    savedAt: Number(parsed.savedAt || 0),
    fileName: parsed.fileName || "",
    data,
    source: source || parsed.source || ""
  };
}

function chooseNewestMenuPayload(current, candidate) {
  if (!candidate) return current;
  if (!current) return candidate;
  return Number(candidate.savedAt || 0) > Number(current.savedAt || 0) ? candidate : current;
}

async function loadRemoteMenuData() {
  if (!location.protocol.startsWith("http")) return null;
  try {
    const response = await fetch(`${MENU_REMOTE_URL}?v=${Date.now()}`, { cache: "no-store" });
    if (!response.ok) return null;
    return normalizeMenuPayloadObject(await response.json(), "remote");
  } catch (error) {
    console.warn("remote menu load failed", error);
    return null;
  }
}

